class Solution {
public:
    string greatestLetter(string s) {
        unordered_map<char, int> count;
        for (char c : s) {
            count[toupper(c)] += 1;
            count[lower(c)] += 1;
        }
        string result = "";
        for (auto it = count.rbegin(); it != count.rend(); ++it) {
            if (it->second >= 2 && it->first >= result[0]) {
                result = string(1, it->first);
            }
        }
        return result;
    }
};
```

